export {
  TreeItem as Item,
  TreePropsContext as PropsContext,
  TreeRoot as Root,
  useTreePropsContext as usePropsContext,
} from "./tree"
export type {
  TreeItemProps as ItemProps,
  TreeItem as ItemType,
  TreeRootProps as RootProps,
} from "./tree"
export {
  TreeContext as Context,
  TreeDescendantsContext as DescendantsContext,
  useTreeContext as useContext,
  useTreeDescendant as useDescendant,
  useTreeDescendants as useDescendants,
  useTreeItemContext as useItemContext,
} from "./use-tree"
export type { TreeControl as Control } from "./use-tree"

import { defineComponentSlotStyle, focusRingStyle } from "@yamada-ui/react"
import { checkboxStyle } from "../checkbox"

export const treeStyle = defineComponentSlotStyle({
  base: {
    checkbox: { "--indicator-bg": "colors.bg", _disabled: { opacity: "1" } },
    element: {
      color: "{element-color}",
      display: "inline-center",
      gap: "{space}",
    },
    end: {},
    group: { alignItems: "stretch", display: "flex", flexDirection: "column" },
    indicator: {
      color: "{element-color}",
      transformOrigin: "center",
      _animated: {
        transitionDuration: "moderate",
        transitionProperty: "transform",
      },
      _expanded: { transform: "rotate(90deg)" },
      _hidden: { opacity: "0" },
    },
    item: {
      "--element-color": "colors.fg.subtle",
      "--space": "spaces.1",
      "--space-start": "calc({depth-space} * ({level} - 1))",
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
      focusVisibleRing: "none",
      _content: {
        alignItems: "center",
        border: "1px solid transparent",
        cursor: "pointer",
        display: "flex",
        gap: "{gap}",
        pe: "{space}",
        ps: "calc({space-start} + {space})",
        rounded: "{rounded}",
        userSelect: "none",
        _hover: { bg: "bg.subtle" },
      },
      _focusVisible: {
        _content: {
          bg: "bg.subtle",
          ...focusRingStyle.inside,
          boxShadow: "none",
        },
      },
      _disabled: { _content: { layerStyle: "disabled" } },
    },
    label: { flex: "1", textAlign: "left", truncated: true },
    root: {
      alignItems: "stretch",
      display: "flex",
      flexDirection: "column",
    },
    start: {},
  },

  props: {
    /**
     * The shape of the component
     *
     * @default 'rounded'
     */
    shape: {
      circle: {
        item: { "--rounded": "radii.full" },
      },
      rounded: {
        item: { "--rounded": "radii.l1" },
      },
      square: {
        item: { "--rounded": "0" },
      },
    },
    /**
     * If `true`, display guide lines.
     *
     * @default false
     */
    withGuideLine: {
      true: {
        group: {
          position: "relative",
          _before: {
            bg: "{guide-line-color}",
            display: "block",
            h: "full",
            left: "calc({space-guide-line} + {depth-space})",
            position: "absolute",
            transform: "translateX(-50%)",
            w: "px",
            zIndex: "yamcha",
          },
        },
        item: {
          "--space-guide-line": "calc(({space-start} * 2) + {space})",
          _content: { ps: "{space-guide-line}" },
        },
        root: { "--guide-line-color": "colors.border" },
      },
    },
  },

  variants: {
    solid: {
      checkbox: {
        ...checkboxStyle.variants?.solid.root,
        _indicator: checkboxStyle.variants?.solid.indicator,
        _selected: {
          _checked: { "--indicator-border-color": "colorScheme.contrast" },
          _indicator: {
            color: "colorScheme.solid",
            _checked: { bg: "colorScheme.contrast" },
            _indeterminate: { bg: "colorScheme.contrast" },
          },
        },
      },
      item: {
        _selected: {
          _content: {
            layerStyle: "solid",
            "--element-color": "colorScheme.contrast",
          },
          _focusVisible: {
            _content: { borderColor: "{focus-ring-color}" },
          },
        },
      },
    },
    subtle: {
      checkbox: {
        ...checkboxStyle.variants?.solid.root,
        _indicator: checkboxStyle.variants?.solid.indicator,
      },
      item: {
        _selected: {
          _content: {
            layerStyle: "subtle",
            "--element-color": "colorScheme.fg",
          },
          _focusVisible: {
            _content: { borderColor: "{focus-ring-color}" },
          },
        },
      },
    },
  },

  sizes: {
    sm: {
      item: { "--depth-space": "spaces.1.5", "--gap": "spaces.1.5" },
      root: { fontSize: "sm" },
    },
    md: {
      item: { "--depth-space": "spaces.2", "--gap": "spaces.2" },
      root: { fontSize: "md" },
    },
    lg: {
      item: { "--depth-space": "spaces.2", "--gap": "spaces.2" },
      root: { fontSize: "lg" },
    },
  },

  defaultProps: {
    size: "md",
    variant: "subtle",
    shape: "rounded",
    withGuideLine: false,
  },
})

export type TreeStyle = typeof treeStyle

"use client"

import type { ReactElement, ReactNode } from "react"
import type {
  GenericsComponent,
  HTMLProps,
  HTMLStyledProps,
  ThemeProps,
} from "@yamada-ui/react"
import type { CheckboxProps } from "../checkbox"
import type { CollapseProps } from "../collapse"
import type { Loading } from "../loading"
import type { WithTransitionProps } from "../motion"
import type { TreeStyle } from "./tree.style"
import type { UseTreeItemProps, UseTreeProps } from "./use-tree"
import {
  Children,
  cloneElement,
  isValidElement,
  useCallback,
  useMemo,
} from "react"
import {
  createSlotComponent,
  styled,
  cast,
  createContext,
  dataAttr,
  isObject,
  isString,
  type ReactNodeOrFunction,
  runIfFn,
} from "@yamada-ui/react"
import { Checkbox } from "../checkbox"
import { Collapse } from "../collapse"
import { ChevronRightIcon } from "../icon"
import { useLoadingComponent } from "../loading"
import { treeStyle } from "./tree.style"
import {
  TreeContext,
  TreeDescendantsContext,
  TreeItemContext,
  useTree,
  useTreeContext,
  useTreeItem,
} from "./use-tree"

interface TreeCallBackProps {
  disabled?: boolean
  expanded?: boolean
}

type TreeItemReactNode =
  | ReactNodeOrFunction<TreeCallBackProps>
  | {
      group: ReactNodeOrFunction<TreeCallBackProps>
      item?: ReactNodeOrFunction<TreeCallBackProps>
    }
  | {
      item: ReactNodeOrFunction<TreeCallBackProps>
      group?: ReactNodeOrFunction<TreeCallBackProps>
    }

interface TreeItemWithValue extends Omit<TreeItemProps, "children"> {}

interface TreeItemWithChildren extends TreeItemWithValue {
  children: TreeItem[]
}

export type TreeItem = TreeItemWithChildren | TreeItemWithValue

const recursiveTreeItem = (items?: TreeItem[]) => {
  return items?.map((props, index) => {
    const key =
      props.value || (isString(props.label) ? `${props.label}-${index}` : index)

    if ("children" in props) {
      const { children, ...rest } = props

      return (
        <TreeItem key={key} {...rest}>
          {recursiveTreeItem(children)}
        </TreeItem>
      )
    } else {
      return <TreeItem key={key} {...props} />
    }
  })
}

const getReactNodeOrFunction = (
  type: "group" | "item",
  custom?: TreeItemReactNode,
  root?: TreeItemReactNode,
): ReactNodeOrFunction<TreeCallBackProps> => {
  if (isObject(custom) && ("group" in custom || "item" in custom)) {
    return custom[type]
  } else if (custom) {
    return custom
  } else if (isObject(root) && ("group" in root || "item" in root)) {
    return root[type]
  } else {
    return root
  }
}

interface ComponentContext extends Pick<
  TreeRootProps,
  | "animated"
  | "checkboxProps"
  | "endElement"
  | "endElementProps"
  | "groupProps"
  | "indicator"
  | "indicatorHidden"
  | "indicatorProps"
  | "itemProps"
  | "labelProps"
  | "loadingScheme"
  | "size"
  | "startElement"
  | "startElementProps"
> {}

interface ItemComponentContext {
  checkboxProps: TreeCheckboxProps
  endElementProps: TreeEndElementProps
  indicatorProps: TreeIndicatorProps
  labelProps: TreeLabelProps
  startElementProps: TreeStartElementProps
}

const [ItemComponentContext, useItemComponentContext] =
  createContext<ItemComponentContext>({ name: "ItemComponentContext" })

export interface TreeRootProps<Multiple extends boolean = false>
  extends
    HTMLStyledProps<"ul">,
    ThemeProps<TreeStyle>,
    UseTreeProps<Multiple>,
    Pick<
      TreeItemProps,
      | "animated"
      | "checkboxProps"
      | "endElement"
      | "endElementProps"
      | "groupProps"
      | "indicator"
      | "indicatorProps"
      | "labelProps"
      | "loadingScheme"
      | "startElement"
      | "startElementProps"
    > {
  /**
   * If `true`, hide the tree indicator icon for all items.
   *
   * @default false
   */
  indicatorHidden?: boolean
  /**
   * If provided, generate elements based on items.
   */
  items?: TreeItem[]
  /**
   * Props for the item component.
   */
  itemProps?: Omit<
    TreeItemProps,
    "children" | "label" | "open" | "query" | "value"
  >
}

const {
  ComponentContext,
  PropsContext: TreePropsContext,
  useComponentContext,
  usePropsContext: useTreePropsContext,
  withContext,
  withProvider,
} = createSlotComponent<TreeRootProps, TreeStyle, ComponentContext>(
  "tree",
  treeStyle,
)

export { TreePropsContext, useTreePropsContext }

/**
 * `Tree` is a component used to display hierarchical data structures in an expandable tree format.
 *
 * @see https://yamada-ui.com/docs/components/tree
 */
export const TreeRoot = withProvider<"ul", TreeRootProps, "size">(
  <Multiple extends boolean = false>({
    size,
    animated,
    children,
    endElement,
    indicator,
    indicatorHidden,
    items,
    loadingScheme,
    startElement,
    checkboxProps,
    endElementProps,
    groupProps,
    indicatorProps,
    itemProps,
    labelProps,
    startElementProps,
    ...rest
  }: TreeRootProps<Multiple>) => {
    const computedChildren = useMemo(() => {
      if (children) return children

      return recursiveTreeItem(items)
    }, [children, items])
    const {
      activeDescendant,
      checkable,
      checkedValue,
      descendants,
      expandedValue,
      multiple,
      selectedValue,
      getRootProps,
      onActiveDescendant,
      onCheckedChange,
      onCollapseAll,
      onExpandAll,
      onExpandedChange,
      onSearch,
      onSelectedChange,
    } = useTree({ ...rest, children: computedChildren })
    const context = useMemo(
      () => ({
        activeDescendant,
        checkable,
        checkedValue,
        expandedValue,
        multiple,
        selectedValue,
        onActiveDescendant,
        onCheckedChange,
        onCollapseAll,
        onExpandAll,
        onExpandedChange,
        onSearch,
        onSelectedChange,
      }),
      [
        activeDescendant,
        checkable,
        checkedValue,
        expandedValue,
        multiple,
        selectedValue,
        onActiveDescendant,
        onCheckedChange,
        onSearch,
        onCollapseAll,
        onExpandAll,
        onExpandedChange,
        onSelectedChange,
      ],
    )
    const componentContext = useMemo(
      () => ({
        size,
        animated,
        endElement,
        indicator,
        indicatorHidden,
        loadingScheme,
        startElement,
        checkboxProps,
        endElementProps,
        groupProps,
        indicatorProps,
        itemProps,
        labelProps,
        startElementProps,
      }),
      [
        size,
        animated,
        endElement,
        indicator,
        indicatorHidden,
        startElement,
        endElementProps,
        groupProps,
        indicatorProps,
        itemProps,
        labelProps,
        startElementProps,
        checkboxProps,
        loadingScheme,
      ],
    )

    return (
      <TreeDescendantsContext value={descendants}>
        <TreeContext value={context}>
          <ComponentContext value={componentContext}>
            <styled.ul {...getRootProps()} />
          </ComponentContext>
        </TreeContext>
      </TreeDescendantsContext>
    )
  },
  "root",
  { transferProps: ["size"] },
)() as GenericsComponent<{
  <Multiple extends boolean = false>(
    props: TreeRootProps<Multiple>,
  ): ReactElement
}>

export interface TreeItemProps
  extends HTMLStyledProps<"div">, Omit<UseTreeItemProps, "asyncChildren"> {
  /**
   * The label to display in the item.
   */
  label: ReactNode
  /**
   * If `true`, the tree item will be animated.
   *
   * @default false
   */
  animated?: boolean
  /**
   * The element to display at the end of the item.
   */
  endElement?: TreeItemReactNode
  /**
   * The tree indicator icon to use.
   */
  indicator?: ReactNodeOrFunction<TreeCallBackProps>
  /**
   * The loading scheme.
   *
   * @default 'oval'
   */
  loadingScheme?: Loading.Scheme
  /**
   * The element to display at the start of the item.
   */
  startElement?: TreeItemReactNode
  /**
   * Props for the checkbox component.
   */
  checkboxProps?: Omit<CheckboxProps, "checked" | "defaultChecked" | "value">
  /**
   * Props for the end component.
   */
  endElementProps?: TreeEndElementProps
  /**
   * Props for the group component.
   */
  groupProps?: Omit<TreeGroupProps, "children">
  /**
   * Props for the indicator component.
   */
  indicatorProps?: TreeIndicatorProps
  /**
   * Props for the label component.
   */
  labelProps?: TreeLabelProps
  /**
   * Props for the root element.
   */
  rootProps?: HTMLStyledProps<"li">
  /**
   * Props for the start component.
   */
  startElementProps?: TreeStartElementProps
  /**
   * If provided, the tree item will be rendered as an async tree item.
   */
  asyncChildren?: () => Promise<TreeItem[]>
}

export const TreeItem = withContext<"div", TreeItemProps>(
  ({
    className,
    css,
    colorScheme,
    animated: animatedProp,
    asyncChildren: asyncChildrenProp,
    endElement,
    indicator: indicatorProp,
    label,
    loadingScheme,
    query,
    startElement,
    value: valueProp = isString(label) ? label : undefined,
    checkboxProps,
    endElementProps,
    groupProps,
    indicatorProps,
    labelProps,
    rootProps,
    startElementProps,
    ...rest
  }) => {
    const { checkable } = useTreeContext()
    const componentContext = useComponentContext()
    const Loading = useLoadingComponent(
      loadingScheme ?? componentContext.loadingScheme ?? "oval",
    )
    const animated = animatedProp ?? componentContext.animated
    const indicator = indicatorProp ?? componentContext.indicator
    const groupStartElement = getReactNodeOrFunction(
      "group",
      startElement,
      componentContext.startElement,
    )
    const groupEndElement = getReactNodeOrFunction(
      "group",
      endElement,
      componentContext.endElement,
    )
    const itemStartElement = getReactNodeOrFunction(
      "item",
      startElement,
      componentContext.startElement,
    )
    const itemEndElement = getReactNodeOrFunction(
      "item",
      endElement,
      componentContext.endElement,
    )
    const asyncChildren = useCallback(async () => {
      const items = await asyncChildrenProp?.()

      return recursiveTreeItem(items)
    }, [asyncChildrenProp])
    const {
      branchOpen,
      children,
      disabled,
      group,
      groupLoading,
      groupOpen,
      level,
      props,
      value,
      getCheckboxProps,
      getGroupItemProps,
      getGroupProps,
      getIndicatorProps,
      getItemProps,
      getLabelProps,
      onGroupClose,
      onGroupOpen,
      onGroupToggle,
    } = useTreeItem({
      ...componentContext.itemProps,
      ...rest,
      asyncChildren: asyncChildrenProp ? asyncChildren : undefined,
      query: query ?? (isString(label) ? label : undefined),
      value: valueProp,
    })
    const itemProps = {
      className,
      css,
      colorScheme,
      "--level": level.toString(),
      ...rootProps,
    }
    const callbackProps = { disabled, expanded: groupOpen }
    const context = useMemo(
      () => ({
        branchOpen,
        groupOpen,
        level,
        value,
        onGroupClose,
        onGroupOpen,
        onGroupToggle,
      }),
      [
        branchOpen,
        groupOpen,
        level,
        value,
        onGroupClose,
        onGroupOpen,
        onGroupToggle,
      ],
    )
    const itemComponentContext = useMemo(
      () => ({
        checkboxProps: {
          size: componentContext.size,
          ...getCheckboxProps({
            ...componentContext.checkboxProps,
            ...checkboxProps,
          }),
        },
        endElementProps: {
          ...componentContext.endElementProps,
          ...endElementProps,
        },
        indicatorProps: {
          ...getIndicatorProps({
            ...componentContext.indicatorProps,
            ...indicatorProps,
          }),
        },
        labelProps: {
          ...getLabelProps({
            ...componentContext.labelProps,
            ...labelProps,
          }),
        },
        startElementProps: {
          ...componentContext.startElementProps,
          ...startElementProps,
        },
      }),
      [
        checkboxProps,
        componentContext.checkboxProps,
        componentContext.endElementProps,
        componentContext.indicatorProps,
        componentContext.labelProps,
        componentContext.size,
        componentContext.startElementProps,
        endElementProps,
        getCheckboxProps,
        getIndicatorProps,
        getLabelProps,
        indicatorProps,
        labelProps,
        startElementProps,
      ],
    )

    return (
      <TreeItemContext value={context}>
        <ItemComponentContext value={itemComponentContext}>
          {group ? (
            <styled.li {...getGroupItemProps(itemProps)}>
              <styled.div data-content {...props}>
                <TreeIndicator data-animated={dataAttr(animated)}>
                  {groupLoading ? (
                    <Loading />
                  ) : (
                    runIfFn(indicator, callbackProps)
                  )}
                </TreeIndicator>
                {checkable ? <TreeCheckbox /> : null}
                {groupStartElement ? (
                  <TreeStartElement>
                    {runIfFn(groupStartElement, callbackProps)}
                  </TreeStartElement>
                ) : null}
                {label ? <TreeLabel>{label}</TreeLabel> : null}
                {groupEndElement ? (
                  <TreeEndElement>
                    {runIfFn(groupEndElement, callbackProps)}
                  </TreeEndElement>
                ) : null}
              </styled.div>

              <TreeGroup
                duration={!animated ? 0 : undefined}
                open={groupOpen}
                {...getGroupProps({
                  ...componentContext.groupProps,
                  ...groupProps,
                })}
              >
                {children}
              </TreeGroup>
            </styled.li>
          ) : (
            <styled.li {...getItemProps(itemProps)}>
              <styled.div data-content {...props}>
                <TreeIndicator data-hidden />
                {checkable ? <TreeCheckbox /> : null}
                {itemStartElement ? (
                  <TreeStartElement>
                    {runIfFn(itemStartElement, callbackProps)}
                  </TreeStartElement>
                ) : null}
                {label ? <TreeLabel>{label}</TreeLabel> : null}
                {itemEndElement ? (
                  <TreeEndElement>
                    {runIfFn(itemEndElement, callbackProps)}
                  </TreeEndElement>
                ) : null}
              </styled.div>
            </styled.li>
          )}
        </ItemComponentContext>
      </TreeItemContext>
    )
  },
  "item",
)()

interface TreeGroupProps
  extends
    Omit<HTMLStyledProps<"ul">, "transition">,
    Pick<CollapseProps, "animationOpacity" | keyof WithTransitionProps> {}

const TreeGroup = withContext<"ul", TreeGroupProps>((props) => {
  return <Collapse as="ul" {...cast<CollapseProps>(props)} />
}, "group")()

interface TreeIndicatorProps extends HTMLStyledProps<"svg"> {}

const TreeIndicator = withContext<"svg", TreeIndicatorProps>(
  ({ children = <ChevronRightIcon />, ...rest }) => {
    const { indicatorHidden } = useComponentContext()

    if (indicatorHidden) return null

    if (isValidElement<HTMLProps<"svg">>(children))
      return cloneElement(children, { ...rest, ...children.props })

    return Children.count(children) > 1 ? Children.only(null) : null
  },
  "indicator",
)(undefined, (props) => {
  const { indicatorProps } = useItemComponentContext()

  return { ...indicatorProps, ...props }
})

interface TreeCheckboxProps extends CheckboxProps {}

const TreeCheckbox = withContext<"input", TreeCheckboxProps>(
  Checkbox,
  "checkbox",
)(undefined, (props) => {
  const { checkboxProps } = useItemComponentContext()

  return { ...checkboxProps, ...props }
})

interface TreeStartElementProps extends HTMLStyledProps {}

const TreeStartElement = withContext<"div", TreeStartElementProps>("div", {
  name: "StartElement",
  slot: ["element", "start"],
})(undefined, (props) => {
  const { startElementProps } = useItemComponentContext()

  return { ...startElementProps, ...props }
})

interface TreeEndElementProps extends HTMLStyledProps {}

const TreeEndElement = withContext<"div", TreeEndElementProps>("div", {
  name: "EndElement",
  slot: ["element", "end"],
})(undefined, (props) => {
  const { endElementProps } = useItemComponentContext()

  return { ...endElementProps, ...props }
})

interface TreeLabelProps extends HTMLStyledProps<"span"> {}

const TreeLabel = withContext<"span", TreeLabelProps>("span", "label")(
  undefined,
  (props) => {
    const { labelProps } = useItemComponentContext()

    return { ...labelProps, ...props }
  },
)

"use client"

import type {
  ChangeEvent,
  KeyboardEvent,
  MouseEvent,
  ReactNode,
  RefObject,
  SetStateAction,
} from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import type { Descendant, Descendants } from "../../hooks/use-descendants"
import type { UseDisclosureProps } from "../../hooks/use-disclosure"
import type { UseCheckboxProps } from "../checkbox"
import { Children, useCallback, useRef, useState } from "react"
import { useAsyncCallback } from "../../hooks/use-async-callback"
import { useControllableState } from "../../hooks/use-controllable-state"
import { createDescendants } from "../../hooks/use-descendants"
import { useDisclosure } from "../../hooks/use-disclosure"
import {
  ariaAttr,
  assignRef,
  createContext,
  cx,
  dataAttr,
  filterEmpty,
  handlerAll,
  isArray,
  isInputElement,
  isUndefined,
  match,
  mergeRefs,
  runKeyAction,
  setAttribute,
  useIds,
  useSafeLayoutEffect,
} from "@yamada-ui/react"

export interface TreeControl {
  collapse: () => void
  expand: () => void
}

interface TreeDescendantProps {
  expanded: boolean
  group: boolean
  id: string
  value: string
  query?: string
}

const {
  DescendantsContext: TreeDescendantsContext,
  useDescendant: useTreeDescendant,
  useDescendants: useTreeDescendants,
} = createDescendants<HTMLElement, TreeDescendantProps>()

export { TreeDescendantsContext, useTreeDescendant, useTreeDescendants }

interface TreeContext extends Omit<
  UseTreeReturn,
  "descendants" | "getRootProps"
> {}

const [TreeContext, useTreeContext] = createContext<TreeContext>({
  name: "TreeContext",
})

export { TreeContext, useTreeContext }

interface TreeItemContext extends Pick<
  UseTreeItemReturn,
  | "branchOpen"
  | "groupOpen"
  | "level"
  | "onGroupClose"
  | "onGroupOpen"
  | "onGroupToggle"
  | "value"
> {}

const [TreeItemContext, useTreeItemContext] = createContext<TreeItemContext>({
  name: "TreeItemContext",
  strict: false,
})

export { TreeItemContext, useTreeItemContext }

export interface UseTreeProps<
  Multiple extends boolean = false,
> extends HTMLProps<"ul"> {
  /**
   * If `true`, the tree will allow checkable items.
   *
   * @default false
   */
  checkable?: boolean
  /**
   * The checked value of the tree.
   */
  checkedValue?: string[]
  /**
   * Ref of the tree callbacks.
   */
  controlRef?: RefObject<null | TreeControl>
  /**
   * The initial checked value of the tree.
   */
  defaultCheckedValue?: string[]
  /**
   * The initial expanded value of the tree.
   */
  defaultExpandedValue?: string[]
  /**
   * The initial selected value of the tree.
   */
  defaultSelectedValue?: Multiple extends true ? string[] : string
  /**
   * The expanded value of the tree.
   */
  expandedValue?: string[]
  /**
   * If `true`, the tree will allow multiple selection.
   *
   * @default false
   */
  multiple?: Multiple
  /**
   * The selected value of the tree.
   */
  selectedValue?: Multiple extends true ? string[] : string
  /**
   * The callback invoked when checked value changes.
   */
  onCheckedChange?: (value: string[]) => void
  /**
   * The callback invoked when expanded value changes.
   */
  onExpandedChange?: (value: string[]) => void
  /**
   * The callback invoked when selected value changes.
   */
  onSelectedChange?: (value: Multiple extends true ? string[] : string) => void
}

export const useTree = <Multiple extends boolean = false>({
  checkable = false,
  checkedValue: checkedValueProp,
  children,
  controlRef,
  defaultCheckedValue = [],
  defaultExpandedValue = [],
  defaultSelectedValue,
  expandedValue: expandedValueProp,
  multiple,
  selectedValue: selectedValueProp,
  onCheckedChange: onCheckedChangeProp,
  onExpandedChange: onExpandedChangeProp,
  onSelectedChange: onSelectedChangeProp,
  ...rest
}: UseTreeProps<Multiple> = {}) => {
  type MaybeSelectedValue = Multiple extends true ? string[] : string

  const [selectedValue, setSelectedValue] = useControllableState({
    defaultValue:
      defaultSelectedValue ?? ((multiple ? [] : "") as MaybeSelectedValue),
    value: selectedValueProp,
    onChange: onSelectedChangeProp,
  })
  const [checkedValue, onCheckedChange] = useControllableState({
    defaultValue: defaultCheckedValue,
    value: checkedValueProp,
    onChange: onCheckedChangeProp,
  })
  const [expandedValue, setExpandedValue] = useControllableState({
    defaultValue: defaultExpandedValue,
    value: expandedValueProp,
    onChange: onExpandedChangeProp,
  })
  const descendants = useTreeDescendants()
  const activeDescendant = useRef<Descendant<
    HTMLElement,
    TreeDescendantProps
  > | null>(null)
  const searchRef = useRef<{ value: string; omitValue?: string }>({
    omitValue: undefined,
    value: "",
  })
  const timeoutRef = useRef<any>(null)

  const onExpandAll = useCallback(() => {
    const values = descendants.enabledValues()
    const group = values.filter(({ group }) => group)
    const value = group.map(({ value }) => value)

    setExpandedValue(value)
  }, [descendants, setExpandedValue])

  const onCollapseAll = useCallback(() => {
    setExpandedValue([])
  }, [setExpandedValue])

  const onActiveDescendant = useCallback(
    (
      descendant?: Descendant<HTMLElement, TreeDescendantProps>,
      shouldFocus = true,
    ) => {
      if (!descendant) return

      descendants.values().forEach(({ node }) => {
        node.tabIndex = -1
      })

      activeDescendant.current = descendant
      descendant.node.tabIndex = 0

      if (shouldFocus) descendant.node.focus()
    },
    [descendants],
  )

  const onSearch = useCallback(
    (value: string, omitValue: string) => {
      clearTimeout(timeoutRef.current)

      searchRef.current.value += value

      if (!searchRef.current.omitValue) searchRef.current.omitValue = omitValue

      timeoutRef.current = setTimeout(() => {
        searchRef.current = { omitValue: undefined, value: "" }
      }, 400)

      const values = descendants
        .enabledValues({ expanded: true })
        .filter(
          (descendant) =>
            !isUndefined(descendant.value) &&
            descendant.value !== searchRef.current.omitValue,
        )
      const descendant = values.find(({ query, value }) =>
        match(query ?? value, searchRef.current.value, "startsWith"),
      )

      if (descendant) onActiveDescendant(descendant)
    },
    [descendants, onActiveDescendant],
  )

  const onSelectedChange = useCallback(
    (value: SetStateAction<string | string[]>) => {
      setSelectedValue(value as SetStateAction<MaybeSelectedValue>)
    },
    [setSelectedValue],
  )

  const onExpandedChange = useCallback(
    (value: string) => {
      setExpandedValue((prev) => {
        if (prev.includes(value)) {
          return prev.filter((prevValue) => prevValue !== value)
        } else {
          return [...prev, value]
        }
      })
    },
    [setExpandedValue],
  )

  useSafeLayoutEffect(() => {
    const value = isArray(selectedValue) ? selectedValue.at(0) : selectedValue
    const expandedDescendants = descendants.enabledValues({ expanded: true })

    if (value) {
      const descendant = expandedDescendants.find(
        (descendant) => value === descendant.value,
      )

      if (descendant) {
        onActiveDescendant(descendant, false)
      } else {
        onActiveDescendant(expandedDescendants.at(0), false)
      }
    } else {
      onActiveDescendant(expandedDescendants.at(0), false)
    }
  }, [children])

  assignRef(controlRef, { collapse: onCollapseAll, expand: onExpandAll })

  const getRootProps: PropGetter<"ul"> = useCallback(
    (props) => ({
      "aria-multiselectable": ariaAttr(multiple || checkable),
      children,
      role: "tree",
      ...rest,
      ...props,
    }),
    [multiple, checkable, rest, children],
  )

  return {
    activeDescendant,
    checkable,
    checkedValue,
    descendants,
    expandedValue,
    multiple,
    selectedValue,
    getRootProps,
    onActiveDescendant,
    onCheckedChange,
    onCollapseAll,
    onExpandAll,
    onExpandedChange,
    onSearch,
    onSelectedChange,
  }
}

export type UseTreeReturn = ReturnType<typeof useTree>

const getRootDescendant =
  (descendants: Descendants<HTMLElement, TreeDescendantProps>) =>
  (value: string) => {
    const segments = value.split("/")

    if (segments.length <= 1) return

    const rootValue = segments.at(0)

    return descendants.enabledValues().find(({ value }) => value === rootValue)
  }

const getParentDescendant =
  (descendants: Descendants<HTMLElement, TreeDescendantProps>) =>
  (value: string) => {
    const segments = value.split("/")

    if (segments.length <= 1) return

    const parentValue = segments.slice(0, -1).join("/")

    return descendants
      .enabledValues()
      .find(({ value }) => value === parentValue)
  }

const getChildDescendants =
  (descendants: Descendants<HTMLElement, TreeDescendantProps>) =>
  (value: string) => {
    const children = descendants
      .enabledValues()
      .filter((descendant) => descendant.value.startsWith(value + "/"))
    const values = children
      .map(({ value }) => value)
      .filter((value) => !isUndefined(value))

    return { children, values }
  }

const getParentValues = (value: string) => {
  const segments = value.split("/")

  return segments
    .reduce<string[]>((prev, current) => {
      const prevValue = prev.at(-1)
      return prevValue ? [...prev, [prevValue, current].join("/")] : [current]
    }, [])
    .toReversed()
}

const getCheckbox = (node?: HTMLElement) => {
  const el = node?.querySelector("input[type='checkbox']")

  return isInputElement(el) ? el : null
}

const getAllChecked = (
  descendants: Descendant<HTMLElement, TreeDescendantProps>[],
  trulyValues?: string[],
  falsyValues?: string[],
) => {
  const checked = descendants.map(({ node, value }) => {
    if (value && trulyValues?.includes(value)) return true
    if (value && falsyValues?.includes(value)) return false

    const checkbox = getCheckbox(node)

    return !!checkbox?.checked
  })

  const allChecked = !!checked.length && checked.every(Boolean)
  const indeterminate = checked.some(Boolean) && !allChecked

  return { allChecked, checked, indeterminate }
}

const getRangeValues =
  (descendants: Descendants<HTMLElement, TreeDescendantProps>) =>
  (start: string, end: string) => {
    const values = descendants.enabledValues()
    const [startIndex, endIndex] = [
      values.findIndex((descendant) => descendant.value === start),
      values.findIndex((descendant) => descendant.value === end),
    ].sort((a, b) => a - b)

    return values
      .slice(startIndex, endIndex! + 1)
      .map(({ value }) => value)
      .filter((value) => !isUndefined(value))
      .sort((a, b) => {
        if (a === start && b !== start) return -1
        if (a !== start && b === start) return 1

        return 0
      })
  }

export interface UseTreeItemProps
  extends HTMLProps<"div">, Omit<UseDisclosureProps, "timing"> {
  /**
   * If `true`, the tree item will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The query to search for in the tree item.
   */
  query?: string
  /**
   * The value of the item.
   */
  value?: string
  /**
   * If provided, the tree item will be rendered as an async tree item.
   */
  asyncChildren?: () => Promise<ReactNode>
}

export const useTreeItem = ({
  asyncChildren,
  children: childrenProp,
  defaultOpen,
  disabled = false,
  open: openProp,
  query,
  value: valueProp,
  onClose: onCloseProp,
  onOpen: onOpenProp,
  ...rest
}: UseTreeItemProps = {}) => {
  const context = useTreeItemContext()
  const {
    activeDescendant,
    checkable,
    checkedValue,
    expandedValue,
    multiple,
    selectedValue,
    onActiveDescendant,
    onCheckedChange,
    onCollapseAll,
    onExpandAll,
    onExpandedChange,
    onSearch,
    onSelectedChange,
  } = useTreeContext()
  const [children, setChildren] = useState<ReactNode>(childrenProp)
  const [indeterminate, setIndeterminate] = useState(false)
  const [itemId, labelId, checkboxId] = useIds()
  const initialAsyncRef = useRef(false)
  const async = !!asyncChildren
  const group = async || Children.count(children) > 0
  const level: number = (context?.level ?? 0) + 1
  const value: string = filterEmpty([context?.value, valueProp]).join("/")
  const nested = !!context?.value
  const selected = isArray(selectedValue)
    ? !!value && selectedValue.includes(value)
    : !!value && selectedValue === value
  const checked = !!value && checkedValue.includes(value)
  const defaultExpanded = !!value && expandedValue.includes(value)
  const {
    open: groupOpen,
    onClose,
    onOpen,
  } = useDisclosure({
    defaultOpen: defaultOpen ?? defaultExpanded,
    open: openProp,
    onClose: onCloseProp,
    onOpen: onOpenProp,
  })
  const branchOpen: boolean[] = nested
    ? [...context.branchOpen, groupOpen]
    : [groupOpen]
  const { descendants, register } = useTreeDescendant({
    id: itemId!,
    disabled,
    expanded: branchOpen.slice(0, -1).every(Boolean),
    group,
    query,
    value,
  })

  const [groupLoading, onGroupChildren] = useAsyncCallback(async () => {
    const children = await asyncChildren?.()

    setChildren(children)
  }, [asyncChildren])

  const onSelect = useCallback(
    (
      ev: (
        | Partial<KeyboardEvent<HTMLElement>>
        | Partial<MouseEvent<HTMLElement>>
      ) & { value?: string } = {},
    ) => {
      const selectedValue = ev.value ?? value

      if (disabled || !selectedValue) return

      if (multiple) {
        onSelectedChange((prev) => {
          if (!isArray(prev)) return prev

          if (ev.ctrlKey || ev.metaKey) {
            if (prev.includes(selectedValue)) {
              return prev.filter((prevValue) => prevValue !== selectedValue)
            } else {
              return [...prev, selectedValue]
            }
          } else if (ev.shiftKey && prev[0]) {
            if (prev[0] === selectedValue) return prev

            return getRangeValues(descendants)(prev[0], selectedValue)
          } else {
            return [selectedValue]
          }
        })
      } else {
        onSelectedChange(selectedValue)
      }
    },
    [descendants, disabled, multiple, onSelectedChange, value],
  )

  const onGroupOpen = useCallback(() => {
    if (disabled || !value) return

    if (async && !initialAsyncRef.current) {
      initialAsyncRef.current = true

      onGroupChildren()
        .then(() => {
          onOpen()
          onExpandedChange(value)
        })
        .catch(() => {
          initialAsyncRef.current = false
        })
    } else {
      onOpen()
      onExpandedChange(value)
    }
  }, [disabled, async, onGroupChildren, onOpen, onExpandedChange, value])

  const onGroupClose = useCallback(() => {
    if (disabled || !value) return

    onClose()
    onExpandedChange(value)
  }, [disabled, onClose, onExpandedChange, value])

  const onGroupToggle = useCallback(() => {
    if (groupOpen) {
      onGroupClose()
    } else {
      onGroupOpen()
    }
  }, [groupOpen, onGroupClose, onGroupOpen])

  const onKeyDown = useCallback(
    (ev: KeyboardEvent<HTMLElement>) => {
      if (disabled || !value) return

      runKeyAction(ev, {
        a: () => {
          if (!multiple || !(ev.ctrlKey || ev.metaKey)) return

          const values = descendants
            .enabledValues()
            .map(({ value }) => value)
            .filter((value) => !isUndefined(value))

          onSelectedChange(values)
        },
        ArrowDown: () => {
          if ((ev.ctrlKey || ev.metaKey) && ev.shiftKey) {
            onExpandAll()
          } else {
            const descendant = descendants.enabledNextValue(
              activeDescendant.current,
              false,
              { expanded: true },
            )

            onActiveDescendant(descendant)

            if (descendant && ev.shiftKey && multiple)
              onSelect({ ctrlKey: true, value: descendant.value })
          }
        },
        ArrowLeft: () => {
          if (group && groupOpen) {
            onGroupClose()
          } else if (nested) {
            const descendant = getParentDescendant(descendants)(value)

            onActiveDescendant(descendant)
          }
        },
        ArrowRight: () => {
          if (!group) return

          if (groupOpen) {
            const descendant = descendants.enabledNextValue(
              activeDescendant.current,
              false,
              { expanded: true },
            )

            onActiveDescendant(descendant)
          } else {
            if (!groupLoading) onGroupOpen()
          }
        },
        ArrowUp: () => {
          if ((ev.ctrlKey || ev.metaKey) && ev.shiftKey) {
            onCollapseAll()

            if (!nested) return

            const descendant = getRootDescendant(descendants)(value)

            onActiveDescendant(descendant)
          } else {
            const descendant = descendants.enabledPrevValue(
              activeDescendant.current,
              false,
              { expanded: true },
            )

            onActiveDescendant(descendant)

            if (descendant && ev.shiftKey && multiple)
              onSelect({ ctrlKey: true, value: descendant.value })
          }
        },
        End: () => {
          const descendant = descendants
            .enabledValues({ expanded: true })
            .at(-1)

          onActiveDescendant(descendant)
        },
        Enter: () => {
          if (group) onGroupToggle()

          onSelect(ev)
        },
        Home: () => {
          const descendant = descendants.enabledValues({ expanded: true }).at(0)

          onActiveDescendant(descendant)
        },
        Space: () => {
          if (group) onGroupToggle()

          onSelect(ev)
        },
      })

      if (ev.key.length !== 1) return
      if (ev.ctrlKey || ev.metaKey || ev.altKey) return

      ev.preventDefault()

      onSearch(ev.key, query ?? value)
    },
    [
      activeDescendant,
      descendants,
      disabled,
      group,
      groupLoading,
      groupOpen,
      multiple,
      nested,
      onActiveDescendant,
      onCollapseAll,
      onExpandAll,
      onGroupClose,
      onGroupOpen,
      onGroupToggle,
      onSearch,
      onSelect,
      onSelectedChange,
      query,
      value,
    ],
  )

  const onItemClick = useCallback(
    (ev: MouseEvent<HTMLLIElement>) => {
      ev.stopPropagation()

      if (disabled || !value) return

      if (group && !groupLoading)
        if (!ev.ctrlKey && !ev.metaKey && !ev.shiftKey) onGroupToggle()

      onSelect(ev)
    },
    [disabled, group, groupLoading, onGroupToggle, onSelect, value],
  )

  const onCheckboxChange = useCallback(
    (ev: ChangeEvent<HTMLInputElement>) => {
      if (disabled || !value) return

      ev.stopPropagation()

      if (group) setIndeterminate(false)

      onCheckedChange((prev) => {
        const target = [value]

        if (group) {
          const { values } = getChildDescendants(descendants)(value)

          target.push(...values)
        }

        if (nested) {
          const parentValues = getParentValues(context.value)
          const parentTarget: string[] = []

          parentValues.forEach((parentValue) => {
            const { children } = getChildDescendants(descendants)(parentValue)
            const { allChecked } = getAllChecked(
              children,
              [...parentTarget, ...(ev.target.checked ? target : [])],
              !ev.target.checked ? target : [],
            )

            if (allChecked) parentTarget.push(parentValue)
          })

          if (!ev.target.checked) parentTarget.push(...parentValues)

          target.push(...parentTarget)
        }

        if (ev.target.checked) {
          return [...new Set([...prev, ...target])]
        } else {
          return prev.filter((prevValue) => !target.includes(prevValue))
        }
      })
    },
    [disabled, group, onCheckedChange, value, nested, descendants, context],
  )

  useSafeLayoutEffect(() => {
    if (defaultExpanded) {
      if (async && !initialAsyncRef.current) {
        initialAsyncRef.current = true

        onGroupChildren()
          .then(() => {
            onOpen()
          })
          .catch(() => {
            initialAsyncRef.current = false
          })
      } else {
        onOpen()
      }
    } else {
      onClose()
    }
  }, [async, defaultExpanded, onClose, onGroupChildren, onOpen])

  useSafeLayoutEffect(() => {
    if (!group || !checkable) return

    const { children } = getChildDescendants(descendants)(value)
    const { indeterminate } = getAllChecked(children)

    setIndeterminate(indeterminate)
  }, [checkedValue])

  useSafeLayoutEffect(() => {
    if (!checkable) return

    const { node } = getParentDescendant(descendants)(value) ?? {}
    const checkbox = getCheckbox(node)

    if (!checkbox) return

    const cleanup = setAttribute(checkbox, "aria-controls", checkboxId)

    return cleanup
  }, [checkable, descendants])

  const getItemProps: PropGetter<"li"> = useCallback(
    ({ ref, "aria-labelledby": ariaLabelledby, ...props } = {}) => ({
      id: itemId,
      ref: mergeRefs(ref, register),
      "aria-disabled": ariaAttr(disabled),
      "aria-labelledby": cx(ariaLabelledby, labelId),
      "aria-level": level,
      "aria-selected": ariaAttr(selected),
      "data-disabled": dataAttr(disabled),
      role: "treeitem",
      tabIndex: -1,
      ...props,
      onClick: handlerAll(props.onClick, onItemClick),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [
      itemId,
      register,
      disabled,
      labelId,
      level,
      selected,
      onItemClick,
      onKeyDown,
    ],
  )

  const getGroupItemProps: PropGetter<"li"> = useCallback(
    (props = {}) => getItemProps({ "aria-expanded": groupOpen, ...props }),
    [getItemProps, groupOpen],
  )

  const getIndicatorProps: PropGetter<"svg"> = useCallback(
    (props) => ({
      "aria-disabled": ariaAttr(disabled),
      "aria-expanded": groupOpen,
      "aria-hidden": true,
      "data-disabled": dataAttr(disabled),
      "data-loading": dataAttr(groupLoading),
      "data-selected": dataAttr(selected),
      role: "presentation",
      ...props,
    }),
    [disabled, groupOpen, selected, groupLoading],
  )

  const getCheckboxProps: PropGetter<UseCheckboxProps> = useCallback(
    ({ "aria-labelledby": ariaLabelledby, ...props } = {}) => ({
      id: checkboxId,
      "aria-labelledby": cx(ariaLabelledby, labelId),
      "data-selected": dataAttr(selected),
      checked,
      disabled,
      indeterminate,
      tabIndex: -1,
      ...props,
      onChange: handlerAll(props.onChange, onCheckboxChange),
    }),
    [
      checkboxId,
      labelId,
      selected,
      checked,
      disabled,
      indeterminate,
      onCheckboxChange,
    ],
  )

  const getGroupProps: PropGetter<"ul"> = useCallback(
    ({ "aria-labelledby": ariaLabelledby, ...props } = {}) => ({
      "aria-busy": ariaAttr(groupLoading),
      "aria-labelledby": cx(ariaLabelledby, labelId),
      "data-disabled": dataAttr(disabled),
      role: "group",
      ...props,
    }),
    [labelId, disabled, groupLoading],
  )

  const getLabelProps: PropGetter<"span"> = useCallback(
    (props = {}) => ({ id: labelId, ...props }),
    [labelId],
  )

  return {
    branchOpen,
    checked,
    children,
    disabled,
    group,
    groupLoading,
    groupOpen,
    indeterminate,
    level,
    props: rest,
    selected,
    value,
    getCheckboxProps,
    getGroupItemProps,
    getGroupProps,
    getIndicatorProps,
    getItemProps,
    getLabelProps,
    onGroupClose,
    onGroupOpen,
    onGroupToggle,
  }
}

export type UseTreeItemReturn = ReturnType<typeof useTreeItem>
